mapper.select:
SELECT notice_id, loginID, title, user, content, reg_date, view_count
FROM notice
WHERE notice_id = #{noticeId}

mapper.update:
UPDATE notice
SET title   = #{title},
    content = #{content}
WHERE notice_id = #{noticeId}

update notice
set view_count = view_count + 1
where notice_id = #{noticeID}
